mapper.select:
SELECT @rownum := @rownum + 1 AS rank, user_id, username, nickname, avatar_url, dimension_value, decimal_value, extra_data, create_time FROM ( SELECT user_id, username, nickname, avatar_url, dimension_value, decimal_value, extra_data, create_time FROM t_leaderboard_data WHERE game_id = #{gameId} AND dimension_code = #{dimensionCode} AND deleted = 0
AND rank_type = #{rankType}
AND rank_date = #{rankDate}
AND rank_month = #{rankMonth}
AND rank_year = #{rankYear}
ORDER BY
dimension_value ASC
dimension_value DESC
LIMIT #{limit} ) AS ranked_data, (SELECT @rownum := 0) AS r

SELECT 
    COUNT(*) + 1 AS userRank,
    best.dimension_value AS userValue,
    total.totalCount
FROM (
    SELECT MAX(dimension_value) AS dimension_value
    FROM t_leaderboard_data
    WHERE user_id = #{userId}
      AND game_id = #{gameId}
      AND dimension_code = #{dimensionCode}
      AND deleted = 0
) AS best,
(
    SELECT COUNT(DISTINCT user_id) AS totalCount
    FROM t_leaderboard_data
    WHERE game_id = #{gameId}
      AND dimension_code = #{dimensionCode}
      AND deleted = 0
) AS total
